p = 10**9 + 7
import math

def inv(k, p):
    return pow(k, p-2, p)

n = int(input())
if n == 1:
    print(1)
elif n == 2:
    print(1)
elif n == 3:
    print(4)
elif n == 6:
    print(120)
else:
    k = 0
    while (1 << (k + 1)) <= n:
        k += 1
    m = 1 << k
    if m + m // 2 <= n:
        m += m // 2
    fac = [1] * (n + 1)
    for i in range(1, n + 1):
        fac[i] = fac[i - 1] * i % p
    ans = fac[n] * inv(m, p) % p
    print(ans)
